import React from "react";

import { Route, Switch, Redirect } from "react-router-dom";
import NavBar from "./components/NavBar";
import Characters from "./views/Characters";
import Home from "./views/Home";
import NewCharacter from "./views/NewCharacter";
import SingleCharacter from "./views/SingleCharacter";
import UpdateCharacter from "./views/UpdateCharacter";

export const Routes = () => {
  return (
    <div>
      <NavBar />
      <Switch>
        <Route exact path="/" component={Home} />
        <Route exact path="/">
          <Redirect to="/" />
        </Route>
        <Route exact path="/BarrysNotesOnBarovia/">
          <Redirect to="/" />
        </Route>
        <Route exact path="/Characters" component={Characters}></Route>
        <Route exact path="/NewCharacter" component={NewCharacter} />
        <Route path="/Character/:id" component={SingleCharacter} />
        <Route path="/CharacterUpdate/:id" component={UpdateCharacter} />
      </Switch>
    </div>
  );
};
