import React from "react";
import { Table } from "react-bootstrap";
import firebase from "./firebase";

const SingleCharacterAbilitiesView = ({ docId }) => {
  const [abilities, setAbilities] = React.useState([]);
  var count = 1;

  React.useEffect(() => {
    if (abilities.length !== 0) {
      return;
    }

    const fetchData = async () => {
      const db = firebase.firestore();
      const data = await db
        .collection("characters/" + docId + "/abilities")
        .get();
      setAbilities(data.docs.map((doc) => ({ id: doc.id, ...doc.data() })));
    };
    fetchData();
    console.log(abilities);
  }, []);

  return (
    <div>
      <div className="single-character-container-table">
        <h1>ABILITIES</h1> length: {abilities.length}
        <Table striped bordered hover variant="dark">
          <thead>
            <tr>
              <th>#</th>
              <th>Name</th>
              <th>Description</th>
            </tr>
          </thead>
          <tbody>
            {abilities.map((ability) => (
              <tr>
                <td>{count++}</td>
                <td>{ability.name}</td>
                <td>{ability.description}</td>
              </tr>
            ))}
          </tbody>
        </Table>
      </div>
    </div>
  );
};

export default SingleCharacterAbilitiesView;

